          )
),

appointments as
(
    select 
        mrns.pat_id,
        mrns.pat_mrn_id,
        f.pat_enc_csn_id,
        trunc( f.appt_dttm ) as appt_date,
        f.prov_id,f.appt_status_c,prc.prc_name,ser.prov_name
    from        f_sched_appt        f 
    inner join  mrns                mrns on  mrns.pat_id       = f.pat_id
    inner join  pat_enc             pe   on  pe.pat_enc_csn_id = f.pat_enc_csn_id
    inner join  clarity_prc         prc  on  prc.prc_id        = f.prc_id
    inner join clarity_ser          ser  on  f.prov_id         = ser.prov_id
    where f.appt_dttm >= ( select start_date from params ) and f.appt_dttm < ( select stop_date from params )
      and upper( prc.prc_name ) not like '%PHONE%'
      and f.appt_status_c in ( 2, 6 )                                           -- 2 = Completed, 6 = "Arrived"
      and ( f.prov_id IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091'
                                   ,'10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
          or f.prov_id = pe.pcp_prov_id )
),

med_orders as 
(
    select 
        f.pat_mrn_id,
        min( med.ordering_date ) as ordering_date
    FROM        appointments        F 
    INNER JOIN  ORDER_MED           MED  ON  F.PAT_ENC_CSN_ID     = MED.PAT_ENC_CSN_ID
    INNER JOIN  GROUPER_MED_RECS    RECS ON  MED.MEDICATION_ID    = RECS.EXP_MEDS_LIST_ID     
    INNER JOIN  GROUPER_ITEMS       GRP  ON  RECS.GROUPER_ID      = GRP.GROUPER_ID     
    WHERE MED.ORDERING_DATE >= ( select start_date from params ) and MED.ORDERING_DATE < ( select end_date from params ) 
      AND GRP.GROUPER_ID IN ( '5431100420','2100000842','2100000601','119613','106060','107472','110472','113623','117473','120930','123997','112234','115750' ) 
      AND ( MED.RSN_FOR_DISCON_C IS NULL OR MED.RSN_FOR_DISCON_C IN ( '12','5','14','96' ) ) 
    group by
        f.pat_mrn_id
)

/*
select 
    ordr.pat_mrn_id,
    ordr.ordering_date,
    add_months( ordr.ordering_date, 12 ) as ordering_date_plus_12months,
    appt.pat_enc_csn_id,
    appt.appt_date,
    count(*) over ( partition by ordr.pat_mrn_id, ordr.ordering_date ) as mycount
from med_orders          ordr 
inner join appointments  appt  on  appt.pat_mrn_id = ordr.pat_mrn_id
where appt.appt_date > ordr.ordering_date and appt.appt_date < add_months( ordr.ordering_date, 12 )
order by 
    ordr.pat_mrn_id,
    ordr.ordering_date,
    appt.appt_date
*/

--/*
select 
    ordr.pat_mrn_id,
    ordr.ordering_date,
    count(*)
from med_orders          ordr 
inner join appointments  appt  on  appt.pat_mrn_id = ordr.pat_mrn_id
where appt.appt_date > ordr.ordering_date and appt.appt_date < add_months( ordr.ordering_date, 12 )
group by 
    ordr.pat_mrn_id,
    ordr.ordering_date
having count(*) >= 2
--*/

